import React from 'react';
import { Web3Provider } from './contexts/Web3Context';
import Header from './components/Header';
import BridgeForm from './components/BridgeForm';
import { Toaster } from 'react-hot-toast';
import { motion } from 'framer-motion';

function App() {
  return (
    <Web3Provider>
      <div className="min-h-screen bg-dark-950">
        <Header />

        <main className="pt-8 pb-16">
          {/* Hero Section */}
          <section className="text-center mb-16">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8"
            >
            </motion.div>
          </section>

          {/* Bridge Form Section */}
          <section id="bridge" className="mb-16">
            <BridgeForm />
          </section>

          {/* Features Section */}
          <section className="mb-16">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                className="text-center mb-12"
              >
                <h2 className="text-3xl font-bold text-white mb-4">Why Choose Counterstake Bridge?</h2>
                <p className="text-secondary-300 max-w-2xl mx-auto">
                  Our bridge uses a unique counterstake mechanism that ensures security and trustlessness
                  across all supported networks.
                </p>
              </motion.div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: 0.1 }}
                  className="card text-center"
                >
                  <div className="w-12 h-12 bg-primary-600 rounded-lg flex items-center justify-center mx-auto mb-4">
                    <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-semibold text-white mb-2">Trustless Security</h3>
                  <p className="text-secondary-400">
                    No trusted intermediaries. The counterstake mechanism ensures honest behavior
                    through economic incentives.
                  </p>
                </motion.div>

                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: 0.2 }}
                  className="card text-center"
                >
                  <div className="w-12 h-12 bg-accent-600 rounded-lg flex items-center justify-center mx-auto mb-4">
                    <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-semibold text-white mb-2">Fast Transfers</h3>
                  <p className="text-secondary-400">
                    Automated assistant contracts speed up transfers while maintaining
                    security through the counterstake mechanism.
                  </p>
                </motion.div>

                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: 0.3 }}
                  className="card text-center"
                >
                  <div className="w-12 h-12 bg-success-600 rounded-lg flex items-center justify-center mx-auto mb-4">
                    <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-semibold text-white mb-2">Decentralized</h3>
                  <p className="text-secondary-400">
                    Governed by the community through on-chain voting. All parameters
                    can be updated through decentralized governance.
                  </p>
                </motion.div>
              </div>
            </div>
          </section>

          {/* How It Works Section */}
          <section className="mb-16">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                className="text-center mb-12"
              >
                <h2 className="text-3xl font-bold text-white mb-4">How It Works</h2>
                <p className="text-secondary-300 max-w-2xl mx-auto">
                  The counterstake bridge process is simple and secure
                </p>
              </motion.div>

              <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
                {[
                  {
                    step: '1',
                    title: 'Initiate Transfer',
                    description: 'Select source and destination networks, enter amount and destination address.',
                    icon: '🚀',
                  },
                  {
                    step: '2',
                    title: 'Provide Stake',
                    description: 'Deposit required stake (typically 10-20% of transfer amount) as security.',
                    icon: '💰',
                  },
                  {
                    step: '3',
                    title: 'Watchdog Claims',
                    description: 'Automated watchdog bots claim valid transfers and challenge fraudulent ones.',
                    icon: '🤖',
                  },
                  {
                    step: '4',
                    title: 'Receive Tokens',
                    description: 'Tokens are minted on destination chain after successful validation.',
                    icon: '✅',
                  },
                ].map((item, index) => (
                  <motion.div
                    key={item.step}
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: index * 0.1 }}
                    className="card text-center relative"
                  >
                    <div className="absolute -top-4 left-1/2 transform -translate-x-1/2">
                      <div className="w-8 h-8 bg-primary-600 rounded-full flex items-center justify-center">
                        <span className="text-white font-bold text-sm">{item.step}</span>
                      </div>
                    </div>
                    <div className="text-4xl mb-4 mt-4">{item.icon}</div>
                    <h3 className="text-lg font-semibold text-white mb-2">{item.title}</h3>
                    <p className="text-secondary-400 text-sm">{item.description}</p>
                  </motion.div>
                ))}
              </div>
            </div>
          </section>
        </main>

        {/* Footer */}
        <footer className="bg-dark-900 border-t border-secondary-800 py-8">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="text-center">
              <p className="text-secondary-400 text-sm">
                © 2024 Counterstake Bridge. Built with ❤️ for the decentralized future.
              </p>
            </div>
          </div>
        </footer>

        {/* Toast Notifications */}
        <Toaster
          position="top-right"
          toastOptions={{
            duration: 4000,
            style: {
